// BTTree types — Figma node 2481:7383
import 'package:flutter/widgets.dart';

/// Tri-state for tree node checkboxes.
enum BTTreeItemCheckState { unchecked, indeterminate, checked }

/// Data model for a single node in the tree.
///
/// Provide [children] to make the node expandable — the arrow is shown
/// automatically. Omit [checkState] (leave it `null`) to hide the checkbox.
/// Supply [body] to render fully custom content in the row's main area;
/// [label] is used as fallback when [body] is absent.
///
/// ```dart
/// BTTreeNode(
///   key: 'q1',
///   label: 'Q1 2026.pdf',
///   icon: const Icon(Icons.description, size: 16),
///   checkState: BTTreeItemCheckState.checked,
///   onCheck: (s) => setState(() => _q1 = s),
/// )
///
/// // Custom body — label + status badge in a Row:
/// BTTreeNode(
///   key: 'srv1',
///   body: Row(children: [
///     Expanded(child: Text('Production API')),
///     _StatusBadge('Active'),
///   ]),
/// )
/// ```
class BTTreeNode {
  const BTTreeNode({
    this.key,
    this.label,
    this.body,
    this.icon,
    this.initiallyExpanded = false,
    this.selected = false,
    this.disabled = false,
    this.checkState,
    this.onPress,
    this.onCheck,
    this.children,
  });

  /// Optional unique key; used by the widget tree as [ValueKey].
  final String? key;

  /// Row label text — optional when [body] is provided.
  final String? label;

  /// Custom content widget rendered in the row's main area (replaces [label]).
  /// Use closures or [StatefulWidget] to bind reactive state.
  final Widget? body;

  /// Optional 16×16 icon widget.
  final Widget? icon;

  /// Whether the node starts expanded. Defaults to `false`.
  final bool initiallyExpanded;

  /// Render with brand-subtle selected background.
  final bool selected;

  /// Disable all interaction (0.45 opacity).
  final bool disabled;

  /// Checkbox tri-state. `null` = no checkbox shown.
  /// Clicking [indeterminate] always transitions to [unchecked].
  final BTTreeItemCheckState? checkState;

  /// Called when the row body is tapped (not the arrow or checkbox).
  final VoidCallback? onPress;

  /// Called when the checkbox state changes. Receives [checked] or [unchecked]
  /// — never [indeterminate].
  final ValueChanged<BTTreeItemCheckState>? onCheck;

  /// Child nodes — presence auto-enables the expand/collapse arrow.
  final List<BTTreeNode>? children;
}

// BTTree — Figma node 2481:7383
import 'package:btech_tokens/btech_tokens.dart';
import '../checkbox/checkbox.widget.dart';
import 'package:btech_ui/src/components/molecules/tree/tree.types.dart';
import 'package:flutter/material.dart';

/// Recursive data-driven tree component.
///
/// Pass a list of [BTTreeNode] objects. Nesting depth is inferred from
/// [children] — no `level` prop required. Expand/collapse state is managed
/// internally with an [AnimatedSize] transition.
///
/// ```dart
/// BTTree(
///   nodes: [
///     BTTreeNode(
///       label: 'Documents',
///       initiallyExpanded: true,
///       children: [
///         BTTreeNode(
///           label: 'Reports',
///           icon: const Icon(Icons.folder, size: 16),
///           children: [
///             BTTreeNode(
///               label: 'Q1 2026.pdf',
///               checkState: BTTreeItemCheckState.checked,
///               onCheck: (s) => setState(() => _q1 = s),
///             ),
///           ],
///         ),
///         BTTreeNode(label: 'Invoices', selected: true),
///       ],
///     ),
///     const BTTreeNode(label: 'Settings'),
///   ],
/// )
/// ```
class BTTree extends StatelessWidget {
  const BTTree({
    required this.nodes,
    super.key,
  });

  final List<BTTreeNode> nodes;

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: nodes
          .asMap()
          .entries
          .map(
            (e) => _BTTreeNodeWidget(
              node: e.value,
              level: 1,
              key: ValueKey(e.value.key ?? e.value.label ?? 'root_${e.key}'),
            ),
          )
          .toList(),
    );
  }
}

// ─── Private recursive node widget ─────────────────────────────────────────

class _BTTreeNodeWidget extends StatefulWidget {
  const _BTTreeNodeWidget({
    required this.node,
    required this.level,
    super.key,
  });

  final BTTreeNode node;
  final int level;

  @override
  State<_BTTreeNodeWidget> createState() => _BTTreeNodeWidgetState();
}

class _BTTreeNodeWidgetState extends State<_BTTreeNodeWidget> {
  late bool _isOpen;
  bool _isHovered = false;
  bool _isPressed = false;

  @override
  void initState() {
    super.initState();
    _isOpen = widget.node.initiallyExpanded;
  }

  bool get _hasChildren =>
      widget.node.children != null && widget.node.children!.isNotEmpty;

  // Inline-start padding formula: 4 + (level - 1) × 24 dp
  double get _paddingStart {
    final clamped = widget.level.clamp(1, 8);
    return 4.0 + (clamped - 1) * 24.0;
  }

  // Background color — follows Figma state priority
  // Per CLAUDE.md §12: use plain Container + setState, NOT AnimatedContainer.
  Color _bgColor(BTColorTheme colors) {
    if (widget.node.selected ||
        widget.node.checkState == BTTreeItemCheckState.checked) {
      return colors.brand.primarySubtle;
    }
    if (!widget.node.disabled && (_isPressed || _isHovered)) {
      return colors.bg.secondary;
    }
    return _levelBg(colors);
  }

  // Level-based default background (level 1 = white, 2–8 = lGrey steps)
  Color _levelBg(BTColorTheme colors) {
    switch (widget.level.clamp(1, 8)) {
      case 1:
        return colors.bg.primary;
      case 2:
        return const Color(0xFFF9F9FA); // --color-l-grey-50
      case 3:
        return const Color(0xFFF3F4F5); // --color-l-grey-100
      case 4:
        return const Color(0xFFECEEF0); // --color-l-grey-150
      case 5:
        return const Color(0xFFE6E8EB); // --color-l-grey-200
      case 6:
        return const Color(0xFFDADDE1); // --color-l-grey-300
      case 7:
        return const Color(0xFFCDD1D7); // --color-l-grey-400
      case 8:
        return const Color(0xFFC1C6CD); // --color-l-grey-500
      default:
        return colors.bg.primary;
    }
  }

  void _handleRowTap() {
    if (widget.node.disabled) return;
    // Tapping anywhere on the row toggles expand/collapse when children exist.
    if (_hasChildren) setState(() => _isOpen = !_isOpen);
    widget.node.onPress?.call();
  }

  void _handleCheckTap() {
    if (widget.node.disabled) return;
    final current =
        widget.node.checkState ?? BTTreeItemCheckState.unchecked;
    // Standard tree: unchecked → checked; checked | indeterminate → unchecked.
    final next = switch (current) {
      BTTreeItemCheckState.unchecked => BTTreeItemCheckState.checked,
      BTTreeItemCheckState.checked => BTTreeItemCheckState.unchecked,
      BTTreeItemCheckState.indeterminate => BTTreeItemCheckState.unchecked,
    };
    widget.node.onCheck?.call(next);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final showCheckbox = widget.node.checkState != null;

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Row ─────────────────────────────────────────────────────────────
        MouseRegion(
          cursor: widget.node.disabled
              ? SystemMouseCursors.forbidden
              : SystemMouseCursors.click,
          onEnter: widget.node.disabled
              ? null
              : (_) => setState(() => _isHovered = true),
          onExit: widget.node.disabled
              ? null
              : (_) => setState(() => _isHovered = false),
          child: GestureDetector(
            onTap: _handleRowTap,
            onTapDown: widget.node.disabled
                ? null
                : (_) => setState(() => _isPressed = true),
            onTapUp: widget.node.disabled
                ? null
                : (_) => setState(() => _isPressed = false),
            onTapCancel: widget.node.disabled
                ? null
                : () => setState(() => _isPressed = false),
            child: Opacity(
              opacity: widget.node.disabled ? 0.45 : 1.0,
              child: Container(
                color: _bgColor(colors),
                padding: EdgeInsetsDirectional.only(
                  start: _paddingStart,
                  end: 8.0,
                  top: 8.0,
                  bottom: 8.0,
                ),
                child: Row(
                  children: [
                    // Arrow / spacer
                    if (_hasChildren)
                      GestureDetector(
                        onTap: widget.node.disabled
                            ? null
                            : () => setState(() => _isOpen = !_isOpen),
                        behavior: HitTestBehavior.opaque,
                        child: SizedBox(
                          width: 16.0,
                          height: 16.0,
                          child: AnimatedRotation(
                            turns: _isOpen ? 0.0 : -0.25, // 0° ↓ / -90° →
                            duration: const Duration(milliseconds: 150),
                            child: Icon(
                              Icons.keyboard_arrow_down,
                              size: 16,
                              color: colors.text.secondary,
                            ),
                          ),
                        ),
                      )
                    else
                      SizedBox(width: 16.0, height: 16.0),

                    SizedBox(width: 8.0),

                    // Checkbox — pass onChanged directly so BTCheckbox's
                    // internal GestureDetector fires correctly.
                    if (showCheckbox) ...[
                      BTCheckbox(
                        checked: widget.node.checkState ==
                            BTTreeItemCheckState.checked,
                        indeterminate: widget.node.checkState ==
                            BTTreeItemCheckState.indeterminate,
                        disabled: widget.node.disabled,
                        onChanged: (_) => _handleCheckTap(),
                      ),
                      SizedBox(width: 8.0),
                    ],

                    // Icon
                    if (widget.node.icon != null) ...[
                      SizedBox(
                        width: 16.0,
                        height: 16.0,
                        child: widget.node.icon,
                      ),
                      SizedBox(width: 8.0),
                    ],

                    // Body (custom content) or label fallback
                    Expanded(
                      child: widget.node.body ??
                          Text(
                            widget.node.label ?? '',
                            style: TextStyle(
                              fontSize: 14.0,
                              fontWeight: FontWeight.w500,
                              height: 1.14,
                              color: colors.text.primary,
                            ),
                            overflow: TextOverflow.ellipsis,
                          ),
                    ),
                  ],
                ),
              ),
            ),
          ),
        ),

        // ── Children (AnimatedSize for smooth height transition) ──────────
        if (_hasChildren)
          AnimatedSize(
            duration: const Duration(milliseconds: 200),
            curve: Curves.easeInOut,
            alignment: Alignment.topCenter,
            child: _isOpen
                ? Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: widget.node.children!
                        .asMap()
                        .entries
                        .map(
                          (e) => _BTTreeNodeWidget(
                            node: e.value,
                            level: widget.level + 1,
                            key: ValueKey(
                              e.value.key ??
                                  e.value.label ??
                                  'node_${e.key}',
                            ),
                          ),
                        )
                        .toList(),
                  )
                : const SizedBox.shrink(),
          ),
      ],
    );
  }
}
